// Prepare Prompts con instrucciones para HTTP tools
const fullInput = $input.first().json;
const inputData = fullInput.body || fullInput;
const type = inputData.type;
const request = inputData.request;
const question = inputData.question;

const isChangeRequest = type === 'change_request' && request && request.description;
const isQuestion = type === 'question' && question;

const changeSystemPrompt = `Eres un asistente AI experto en desarrollo web para NeuroInnova.

## HERRAMIENTAS DISPONIBLES (HTTP Requests a GitHub API)

1. **Get File Content** - Lee archivos del repositorio
   - Descripción: "Obtener contenido de {path}"
   - URL: https://api.github.com/repos/clickmediapropy/neuroinnova-cl/contents/{path}
   - Método: GET

2. **Update File** - Actualiza archivos existentes
   - Descripción: "Actualizar {path}"
   - URL: https://api.github.com/repos/clickmediapropy/neuroinnova-cl/contents/{path}
   - Método: PUT
   - Body: {"message": "commit message", "content": "base64_content", "sha": "current_sha"}

3. **Create File** - Crea nuevos archivos
   - Descripción: "Crear {path}"
   - URL: https://api.github.com/repos/clickmediapropy/neuroinnova-cl/contents/{path}
   - Método: PUT
   - Body: {"message": "commit message", "content": "base64_content"}

## PROCESO OBLIGATORIO

1. SIEMPRE usa Get File Content primero para obtener el SHA actual
2. El contenido debe estar en Base64
3. Incluye un mensaje de commit descriptivo
4. Para actualizar, necesitas el SHA del archivo actual

## ESTRUCTURA DEL PROYECTO

- WhatsApp: src/components/ui/WhatsAppButton.tsx (línea 6)
- Header: src/components/layout/Header.tsx
- Footer: src/components/layout/Footer.tsx
- Hero: src/components/sections/Hero.tsx

WhatsApp actual: +595 991 800 886`;

const changeUserPrompt = isChangeRequest ? 
`CAMBIO SOLICITADO: ${request.description}

USA LAS HERRAMIENTAS HTTP PARA:
1. Obtener el archivo actual (GET)
2. Modificar el contenido
3. Actualizar el archivo (PUT con el nuevo contenido en base64)

RECUERDA: Debes codificar el contenido en base64 y usar el SHA actual.` : '';

return [{
  json: {
    systemPrompt: isChangeRequest ? changeSystemPrompt : 'Asistente de NeuroInnova',
    userPrompt: isChangeRequest ? changeUserPrompt : question || '',
    originalData: inputData,
    isChangeRequest
  }
}];

const agentOutput = $input.first().json;
const originalData = $('Prepare Prompts').first().json.originalData;
const isChangeRequest = $('Prepare Prompts').first().json.isChangeRequest;

let response = {
  success: true,
  timestamp: new Date().toISOString()
};

if (isChangeRequest) {
  response.type = 'change_request';
  response.message = 'Cambios procesados exitosamente';
  response.request = originalData.request;

  if (agentOutput.steps) {
    response.actions = agentOutput.steps.map(step => ({
      tool: step.action?.tool,
      input: step.action?.toolInput,
      output: step.observation
    }));
  }

  response.agentSummary = agentOutput.output || agentOutput.text || 'Cambios completados';
} else {
  response.type = 'question';
  response.question = originalData.question;
  response.answer = agentOutput.output || agentOutput.text || 'No se pudo generar una respuesta';
}

return [{json: response}];
